static MARKER_LEVEL_RE: Lazy<Regex> = Lazy::new(|| Regex::new(r"(\d+)").unwrap());
static ATTRIBUTE_RE: Lazy<Regex> =
    Lazy::new(|| Regex::new(r#"^([a-zA-Z0-9\-_]+)="([^"]*)"$"#).unwrap());

static CHAPTER_RE: Lazy<Regex> = Lazy::new(|| Regex::new(r"^(\d+)").unwrap());

// Token is now so small, it can be Copy
#[derive(Debug, Clone, Copy)]
pub struct Token<'i> {
    pub kind: TokenKind,
    pub text: &'i str,
    pub span: (usize, usize),
}

// ParsedToken borrows from the input and has no redundant info
#[derive(Debug, PartialEq, Clone, Serialize)] // Removed Clone, we'll avoid it
pub struct ParsedToken<'i> {
    pub kind: TokenKind, // Store the enum directly
    pub text: &'i str,
    pub span: (usize, usize),
    pub level: Option<&'i str>, // Borrow the level number
    pub content: Vec<ParsedToken<'i>>,
    pub attributes: HashMap<&'i str, &'i str>, // Borrow attributes too
}

// The final result also needs the lifetime
#[derive(Debug, Clone, Serialize)]
pub struct ParsedUSFM<'i> {
    pub intro: Vec<ParsedToken<'i>>,
    pub chapters: HashMap<u32, Vec<ParsedToken<'i>>>,
}
#[derive(Serialize, Clone)]
pub struct OwnedParsedUSFM {
    pub intro: Vec<OwnedParsedToken>,
    pub chapters: HashMap<u32, Vec<OwnedParsedToken>>,
}

#[derive(Serialize, Clone)]
pub struct OwnedParsedToken {
    pub kind: TokenKind, // Store the enum directly
    pub text: String,
    pub span: (usize, usize),
    #[serde(skip_serializing_if = "Option::is_none")]
    pub level: Option<String>, // Borrow the level number
    #[serde(skip_serializing_if = "Vec::is_empty")]
    pub content: Vec<OwnedParsedToken>,
    #[serde(skip_serializing_if = "HashMap::is_empty")]
    pub attributes: HashMap<String, String>, // Borrow attributes too
}
impl<'i> From<ParsedUSFM<'i>> for OwnedParsedUSFM {
    fn from(borrowed: ParsedUSFM<'i>) -> Self {
        OwnedParsedUSFM {
            intro: borrowed.intro.into_iter().map(|t| t.into()).collect(),
            chapters: borrowed
                .chapters
                .into_iter()
                .map(|(k, v)| (k, v.into_iter().map(|t| t.into()).collect()))
                .collect(),
        }
    }
}

impl<'i> From<ParsedToken<'i>> for OwnedParsedToken {
    fn from(b: ParsedToken<'i>) -> Self {
        OwnedParsedToken {
            kind: b.kind,
            span: b.span,
            text: b.text.to_string(),
            level: b.level.map(|s| s.to_string()),
            content: b.content.into_iter().map(|t| t.into()).collect(),
            attributes: b
                .attributes
                .into_iter()
                .map(|(k, v)| (k.to_string(), v.to_string()))
                .collect(),
        }
    }
}

