fn parse_attribute_pair<'i>(attr_text: &'i str) -> Option<(&'i str, &'i str)> {
    // PERF: Captures now return borrowed &'i str, no String allocation.
    ATTRIBUTE_RE.captures(attr_text).and_then(|caps| {
        let k = caps.get(1)?.as_str();
        let v = caps.get(2)?.as_str();
        Some((k, v))
    })
}

fn create_parsed_token<'i>(token: &Token<'i>) -> ParsedToken<'i> {
    // PERF: No more `format!`, no String clones.
    let level = if is_marker(token.text) {
        MARKER_LEVEL_RE
            .captures(token.text)
            .and_then(|caps| caps.get(1).map(|m| m.as_str()))
    } else {
        None
    };

    ParsedToken {
        kind: token.kind,
        text: token.text,
        span: token.span,
        level,
        content: vec![],
        attributes: HashMap::new(),
    }
}

fn parse_token_stream<'i>(tokens: &[Token<'i>]) -> Vec<ParsedToken<'i>> {
    let mut result: Vec<ParsedToken<'i>> = Vec::new();

    // PERF: The stack now stores indices, not references. This is the key to
    // satisfying the borrow checker. It represents the path to the current parent.
    // e.g., `[0, 2]` means `result[0].content[2]`
    let mut stack: Vec<usize> = Vec::new();

    for token in tokens {
        // --- Handle Attribute Tokens ---
        // Attributes apply to the most recently added node at the current depth.
        if token.kind == TokenKind::AttrPair {
            // 1. Get a mutable reference to the current parent's content Vec.
            let mut current_level = &mut result;
            for &index in &stack {
                current_level = &mut current_level[index].content;
            }

            // 2. Modify the last node in that Vec.
            if let Some(last_node) = current_level.last_mut() {
                if is_marker(last_node.text) {
                    if let Some((k, v)) = parse_attribute_pair(token.text) {
                        last_node.attributes.insert(k, v);
                    }
                }
            }
            continue;
        }

        // --- Handle Closing Markers ---
        if is_end_marker(token.kind) {
            // A closing tag just means we go up one level in the hierarchy.
            stack.pop();
            continue;
        }

        // --- Handle Opening / Standalone Tokens ---
        let parsed_token = create_parsed_token(token);

        // 1. Get a mutable reference to the parent's content Vec by walking the path.
        // This is the "get current" step.
        let parent_content = {
            let mut current = &mut result;
            for &index in &stack {
                // Get the node at the index, then get a reference to its content vec
                current = &mut current[index].content;
            }
            current
        };

        // 2. Move the new token into the parent's content.
        parent_content.push(parsed_token);

        // 3. If the token we just added is a container, update the path.
        // The new path is the old path plus the index of the element we just added.
        if TOKENS_EXPECTING_CLOSE.contains(&token.kind) {
            let new_index = parent_content.len() - 1;
            stack.push(new_index);
        }
    }

    result
}

pub fn is_marker(text: &str) -> bool {
    text.starts_with('\\')
}

