// PERF: The function now works with the borrowed `ParsedToken<'i>`
pub fn organize_by_chapters<'i>(tokens: Vec<ParsedToken<'i>>) -> ParsedUSFM<'i> {
    // 1. PRE-COMPUTATION PASS: Find the start index of every chapter marker.
    // We iterate once to find all `TokenKind::C` and store their positions.
    let chapter_start_indices: Vec<usize> = tokens
        .iter()
        .enumerate()
        .filter(|(_i, token)| token.kind == TokenKind::C)
        .map(|(i, _token)| i)
        .collect();

    // If there are no chapter markers at all, the entire document is the intro.
    if chapter_start_indices.is_empty() {
        return ParsedUSFM {
            intro: tokens, // We can move the whole vector, no clone needed.
            chapters: HashMap::new(),
        };
    }

    // --- SLICING AND ORGANIZATION ---

    // 2. The intro is everything from the beginning up to the first chapter marker.
    let first_chapter_index = chapter_start_indices[0];
    let intro = tokens[0..first_chapter_index].to_vec(); // .to_vec() creates an owned copy

    // 3. Create chapter chunks using the pre-computed indices.
    let mut chapters = HashMap::new();

    // Create an iterator that gives us the start and end index for each chapter's slice.
    // We chain the list of start indices with the total length of the token vec,
    // then use `.windows(2)` to create pairs like `[start1, start2]`, `[start2, start3]`, etc.
    let ranges = chapter_start_indices
        .iter()
        .map(|&i| i) // Convert `&usize` to `usize`
        .chain(std::iter::once(tokens.len()));

    for window in ranges.collect::<Vec<_>>().windows(2) {
        let start_index = window[0];
        let end_index = window[1];

        // Get the slice of tokens for the current chapter.
        let chapter_tokens = &tokens[start_index..end_index];

        // The first token is `\c`. The token *after* it should contain the number.
        // A robust parser would validate this structure carefully.
        if chapter_tokens.len() > 1 {
            let number_token = &chapter_tokens[1];
            // Trim whitespace and parse the text to a u32 for the HashMap key.
            if let Ok(chapter_num) = number_token.text.trim().parse::<u32>() {
                // Insert an owned copy of the slice into the map.
                chapters.insert(chapter_num, chapter_tokens.to_vec());
            } else {
                // Handle the case where a `\c` is not followed by a valid number.
                // For now, we'll just skip this malformed chapter.
                println!("Warning: Malformed chapter marker at index {}", start_index);
            }
        }
    }

    ParsedUSFM { intro, chapters }
}

pub fn parse_usfm(input: &str) -> ParsedUSFM {
    let lexer = TokenKind::lexer(input);
    let tokens: Vec<Token> = lexer
        .spanned()
        .filter_map(|(res_kind, span)| {
            // res_kind: Result<TokenKind, ()>
            let span = (span.start, span.end);
            if let Ok(kind) = res_kind {
                Some(Token {
                    text: &input[span.0..span.1],
                    span,
                    kind,
                })
            } else {
                None // or handle error in some way
            }
        })
        .collect();

    // push_whitespace_onto_prev_token(&mut tokens);

    let parsed_tokens = parse_token_stream(&tokens);
    let organized = organize_by_chapters(parsed_tokens);

    organized
}
